files.test_api.py:
import unittest

from api import build_label


class BuildLabelTest(unittest.TestCase):
    def test_kind_is_required_and_formats_trimmed_value(self):
        self.assertEqual(build_label(' Ada ', kind='invoice'), 'invoice:Ada')

    def test_kind_is_keyword_only(self):
        with self.assertRaises(TypeError):
            build_label('Ada', 'invoice')


if __name__ == '__main__':
    unittest.main()

